  1	import * as React from 'react';
  2	import {
  3	  EnrollDiscoveredApplicationStepNames,
  4	  EnrollDiscoveredApplicationSteps,
  5	} from '@odf/mco/constants';
  6	import { isLabelOnlyOperator } from '@odf/shared/label-expression-selector';
  7	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
  8	import * as _ from 'lodash-es';
  9	import { TFunction } from 'react-i18next';
 10	import {
 11	  Button,
 12	  ButtonVariant,
 13	  Alert,
 14	  AlertVariant,
 15	  useWizardContext,
 16	  WizardFooterWrapper,
 17	} from '@patternfly/react-core';
 18	import {
 19	  EnrollDiscoveredApplicationState,
 20	  ProtectionMethodType,
 21	} from './utils/reducer';
 22	
 23	const validateNamespaceStep = (state: EnrollDiscoveredApplicationState) =>
 24	  !!state.namespace.clusterName &&
 25	  !!state.namespace.namespaces.length &&
 26	  !!state.namespace.name;
 27	
 28	const validateConfigurationStep = (state: EnrollDiscoveredApplicationState) => {
 29	  const { recipe, resourceLabels, protectionMethod } = state.configuration;
 30	  const { recipeName, recipeNamespace } = recipe;
 31	  const { k8sResourceLabelExpressions, pvcLabelExpressions } = resourceLabels;
 32	  const labelExpressions = [
 33	    ...k8sResourceLabelExpressions,
 34	    ...pvcLabelExpressions,
 35	  ];
 36	  const isLabelExpressionsFound =
 37	    k8sResourceLabelExpressions.length && pvcLabelExpressions.length;
 38	  return protectionMethod === ProtectionMethodType.RECIPE
 39	    ? !!recipeName && !!recipeNamespace
 40	    : isLabelExpressionsFound &&
 41	        labelExpressions.every((selector) =>
 42	          isLabelOnlyOperator(selector.operator)
 43	            ? !!selector.key
 44	            : !!selector.key && !!selector.values.length
 45	        );
 46	};
 47	
 48	const validateReplicationStep = (state: EnrollDiscoveredApplicationState) =>
 49	  !_.isEmpty(state.replication.drPolicy);
 50	
 51	const canJumpToNextStep = (
 52	  state: EnrollDiscoveredApplicationState,
 53	  stepName: string,
 54	  t: TFunction
 55	) => {
 56	  switch (stepName) {
 57	    case EnrollDiscoveredApplicationStepNames(t)[
 58	      EnrollDiscoveredApplicationSteps.Namespace
 59	    ]:
 60	      return validateNamespaceStep(state);
 61	    case EnrollDiscoveredApplicationStepNames(t)[
 62	      EnrollDiscoveredApplicationSteps.Configuration
 63	    ]:
 64	      return validateConfigurationStep(state);
 65	    case EnrollDiscoveredApplicationStepNames(t)[
 66	      EnrollDiscoveredApplicationSteps.Replication
 67	    ]:
 68	      return validateReplicationStep(state);
 69	    default:
 70	      return false;
 71	  }
 72	};
 73	
 74	export const EnrollDiscoveredApplicationFooter: React.FC<
 75	  EnrollDiscoveredApplicationFooterProps
 76	> = ({
 77	  state,
 78	  isValidationEnabled,
 79	  onSaveError,
 80	  setIsValidationEnabled,
 81	  onSubmit,
 82	  onCancel,
 83	}) => {
 84	  const { t } = useCustomTranslation();
 85	  const [requestInProgress, setRequestInProgress] = React.useState(false);
 86	  const { activeStep, goToNextStep, goToPrevStep } = useWizardContext();
 87	
 88	  const stepName = activeStep.name as string;
 89	
 90	  const canJumpToNext = canJumpToNextStep(state, stepName, t);
 91	  const validationError = isValidationEnabled && !canJumpToNext;
 92	  const enrollDiscoveredApplicationStepNames =
 93	    EnrollDiscoveredApplicationStepNames(t);
 94	  const isReviewStep =
 95	    stepName ===
 96	    enrollDiscoveredApplicationStepNames[
 97	      EnrollDiscoveredApplicationSteps.Review
 98	    ];
 99	
100	  const moveToNextStep = () => {
101	    if (canJumpToNext) {
102	      setIsValidationEnabled(false);
103	      goToNextStep();
104	    } else {
105	      setIsValidationEnabled(true);
106	    }
107	  };
108	
109	  const handleNext = () => {
110	    if (isReviewStep) {
111	      onSubmit(setRequestInProgress);
112	    } else {
113	      moveToNextStep();
114	    }
115	  };
116	
117	  return (
118	    <>
119	      {validationError && (
120	        <Alert
121	          title={t(
122	            '1 or more mandatory fields are empty. To proceed, fill in the required information.'
123	          )}
124	          variant={AlertVariant.danger}
125	          isInline
126	        />
127	      )}
128	      {!!onSaveError && isReviewStep && (
129	        <Alert title={onSaveError} variant={AlertVariant.danger} isInline />
130	      )}
131	      <WizardFooterWrapper>
132	        <Button
133	          isLoading={requestInProgress}
134	          isDisabled={requestInProgress}
135	          variant={ButtonVariant.primary}
136	          onClick={handleNext}
137	        >
138	          {stepName ===
139	          enrollDiscoveredApplicationStepNames[
140	            EnrollDiscoveredApplicationSteps.Review
141	          ]
142	            ? t('Save')
143	            : t('Next')}
144	        </Button>
145	        {/* Disabling the back button for the first step in wizard */}
146	        <Button
147	          variant={ButtonVariant.secondary}
148	          onClick={goToPrevStep}
149	          isDisabled={activeStep.index === 1 || requestInProgress}
150	        >
151	          {t('Back')}
152	        </Button>
153	        <Button
154	          variant={ButtonVariant.link}
155	          onClick={onCancel}
156	          isDisabled={requestInProgress}
157	        >
158	          {t('Cancel')}
159	        </Button>
160	      </WizardFooterWrapper>
161	    </>
162	  );
163	};
164	
165	type EnrollDiscoveredApplicationFooterProps = {
166	  state: EnrollDiscoveredApplicationState;
167	  isValidationEnabled: boolean;
168	  onSaveError: string;
169	  setIsValidationEnabled: React.Dispatch<React.SetStateAction<boolean>>;
170	  onSubmit: (
171	    setRequestInProgress: React.Dispatch<React.SetStateAction<boolean>>
172	  ) => Promise<void>;
173	  onCancel: () => void;
174	};

